// ━━━ Build and write ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

function buildJson(level, rawWords) {
  // Deduplicate within level
  const seen = new Set();
  const uniqueWords = [];
  for (const w of rawWords) {
    const key = w.w.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    uniqueWords.push(w);
  }

  const words = uniqueWords.map((w, i) => ({
    id: `${level.toLowerCase()}-${String(i + 1).padStart(3, '0')}`,
    word: w.w,
    article: w.a,
    translation: { pt: w.pt, en: w.en },
    category: w.c,
    example: w.ex,
    difficulty: w.d,
    tags: [w.a ? 'substantiv' : 'andere'],
  }));

  return {
    metadata: {
      level,
      source: `Goethe-Institut Wortliste ${level}`,
      sourceUrl: 'https://www.goethe.de/',
      totalWords: words.length,
      lastUpdated: new Date().toISOString().slice(0, 10),
    },
    categories: CATEGORIES,
    words,
  };
}

function deduplicateAcrossLevels(levels) {
  const globalSeen = new Set();
  for (const { level, data } of levels) {
    const before = data.words.length;
    data.words = data.words.filter((w) => {
      const key = w.word.toLowerCase();
      if (globalSeen.has(key)) return false;
      globalSeen.add(key);
      return true;
    });
    // Re-index IDs after dedup
    data.words = data.words.map((w, i) => ({
      ...w,
      id: `${level.toLowerCase()}-${String(i + 1).padStart(3, '0')}`,
    }));
    data.metadata.totalWords = data.words.length;
    const removed = before - data.words.length;
    if (removed > 0) console.log(`  ${level}: removed ${removed} cross-level duplicates`);
  }
}

// Build A1, keep A2 from existing file, build B1/B2/C1
import { readFileSync } from 'fs';

const a2Existing = JSON.parse(readFileSync(join(DATA_DIR, 'wortliste-a2.json'), 'utf-8'));

const a1Data = buildJson('A1', A1_WORDS);
const b1Data = buildJson('B1', B1_WORDS);
const b2Data = buildJson('B2', B2_WORDS);
const c1Data = buildJson('C1', C1_WORDS);

const allLevels = [
  { level: 'A1', data: a1Data },
  { level: 'A2', data: a2Existing },
  { level: 'B1', data: b1Data },
  { level: 'B2', data: b2Data },
  { level: 'C1', data: c1Data },
];

console.log('Before dedup:');
for (const { level, data } of allLevels) {
  console.log(`  ${level}: ${data.words.length} words`);
}

deduplicateAcrossLevels(allLevels);

console.log('\nAfter dedup:');
let total = 0;
for (const { level, data } of allLevels) {
  console.log(`  ${level}: ${data.words.length} words`);
  total += data.words.length;
}
console.log(`\n  Total: ${total} unique words`);

// Write files (skip A2, keep original)
for (const { level, data } of allLevels) {
  const filename = `wortliste-${level.toLowerCase()}.json`;
  writeFileSync(join(DATA_DIR, filename), JSON.stringify(data, null, 2) + '\n', 'utf-8');
  console.log(`  ✅ ${filename} written (${data.words.length} words)`);
}

console.log('\nDone!');
